 import { execSync } from 'child_process';

+/**
+ * Patterns considered dangerous in shell commands. Used to guard against
+ * accidental injection from unsanitized callers before invoking execSync.
+ */
+const DANGEROUS_PATTERNS: RegExp[] = [
+  /rm\s+-rf\s+\//,      // recursive delete from root
+  /:\(\)\s*\{.*\};:/,   // fork bomb
+  /\bmkfs(\.|\s)/,       // filesystem format
+  /\bdd\s+if=.*of=\/dev\//, // raw device write
+  />\s*\/dev\/sd[a-z]/,  // redirect to block device
+  /\bshutdown\b|\breboot\b|\bhalt\b/,
+  /[;&|`$]\s*(curl|wget)\s+[^|]*\|\s*(sh|bash)/, // piped remote exec
+];
+
+/**
+ * Returns true if the given command string matches any known-dangerous pattern.
+ */
+export function isDangerousCommand(command: string): boolean {
+  if (!command || typeof command !== 'string') return true;
+  return DANGEROUS_PATTERNS.some((pattern) => pattern.test(command));
+}
+
+/**
+ * Defensive wrapper around execSync that enforces isDangerousCommand checks
+ * before executing. All internal callers MUST route through this function
+ * rather than calling execSync directly.
+ */
+function safeExecSync(command: string, options: Parameters<typeof execSync>[1]): string | Buffer {
+  if (isDangerousCommand(command)) {
+    throw new Error(`[Runner] Refusing to execute dangerous command: ${command}`);
+  }
+  return execSync(command, options);
+}
