+/**
+ * Mission config validator.
+ * Missions MUST be declarative JSON. This module rejects any mission file
+ * that contains executable hooks (e.g. `eval`, `require`, `exec`, `shell`).
+ */
+import { readFileSync } from 'fs';
+
+const FORBIDDEN_KEYS = ['eval', 'exec', 'shell', 'require', 'spawn', 'cmd'];
+const FORBIDDEN_PATTERNS = [/\beval\s*\(/, /\brequire\s*\(/, /child_process/];
+
+export interface MissionDoc {
+  name: string;
+  description?: string;
+  steps: Array<Record<string, unknown>>;
+}
+
+export function validateMissionObject(doc: unknown): asserts doc is MissionDoc {
+  if (!doc || typeof doc !== 'object') throw new Error('mission must be an object');
+  const d = doc as Record<string, unknown>;
+  if (typeof d.name !== 'string') throw new Error('mission.name must be string');
+  if (!Array.isArray(d.steps)) throw new Error('mission.steps must be array');
+  const json = JSON.stringify(doc);
+  for (const key of FORBIDDEN_KEYS) {
+    if (json.includes(`"${key}"`)) throw new Error(`mission contains forbidden key: ${key}`);
+  }
+  for (const pat of FORBIDDEN_PATTERNS) {
+    if (pat.test(json)) throw new Error(`mission contains forbidden pattern: ${pat}`);
+  }
+}
+
+export function loadAndValidateMission(path: string): MissionDoc {
+  const raw = readFileSync(path, 'utf8');
+  const parsed = JSON.parse(raw);
+  validateMissionObject(parsed);
+  return parsed as MissionDoc;
+}

